import { DeleteForever, WbSunny } from "@mui/icons-material";
import { useDispatch, useSelector } from "react-redux";
import { AddTodo, ChangeChecked, DeleteTodo } from "./store";
import "./App.css";
import { useState } from "react";

function App() {
  let dispatch = useDispatch();
  let store = useSelector((state) => state);
  const [btnState, setBtnState] = useState(0);
  const [addName, updateAddName] = useState("");
  const onChangeAdd = (e) => {
    updateAddName(e.target.value);
  };

  const handleAdd = (e) => {
    e.preventDefault();
    dispatch(AddTodo(addName));
    updateAddName("");
  };

  const handleCheck = (e) => {
    console.log(e);
    dispatch(ChangeChecked(e.target.name));
  };

  const handleDelete = (e) => {
    dispatch(DeleteTodo(e.target.id));
  };

  let data = store.schedule;

  if (btnState === 0) {
    data = store.schedule;
  } else if (btnState === 1) {
    data = data.filter((e) => !e.isCheck);
  } else {
    data = data.filter((e) => e.isCheck);
  }

  return (
    <div className='flex justify-center items-center w-[100vw] h-[100vh] bg-gray-500'>
      <div className='box-border w-[90%] h-[70%] rounded-xl bg-slate-900'>
        <div className='flex items-center h-[15%] justify-between'>
          <WbSunny className='text-white ml-5' />
          <div className='flex gap-5 text-orange-400 mr-5 text-l'>
            <button
              onClick={() => setBtnState(0)}
              className='focus:font-bold focus:underline focus:underline-offset-4 focus:decoration-white'
            >
              All
            </button>
            <button
              onClick={() => setBtnState(1)}
              className='focus:font-bold focus:underline focus:underline-offset-4 focus:decoration-white'
            >
              Avtive
            </button>
            <button
              onClick={() => setBtnState(2)}
              className='focus:font-bold focus:underline focus:underline-offset-4 focus:decoration-white'
            >
              Completed
            </button>
          </div>
        </div>
        <div className='h-[70%] bg-slate-700'>
          <ul className='flex flex-col justify-between text-white text-l font-bold'>
            {data.map((e, i) => (
              <li key={i} className='mt-5 ml-5 w-[90%] flex justify-between'>
                <label>
                  <input
                    name={e.title}
                    className='mr-2'
                    type='checkbox'
                    checked={e.isCheck}
                    onChange={handleCheck}
                  ></input>
                  {e.isCheck ? (
                    <span className='line-through text-gray-600'>
                      {e.title}
                    </span>
                  ) : (
                    e.title
                  )}
                </label>
                <button
                  type='button'
                  id={e.title}
                  name={e.title}
                  onClick={handleDelete}
                >
                  <DeleteForever
                    fontSize='small'
                    className='text-white bg-gray-800 rounded-xl hover:bg-orange-400 hover:scale-110'
                  />
                </button>
              </li>
            ))}
          </ul>
        </div>
        <div className='flex h-[15%] items-center justify-center'>
          <input
            type='text'
            placeholder='Add Todo'
            className='bg-white w-[70%] p-3 rounded-lg rounded-r-none'
            value={addName}
            onChange={onChangeAdd}
          ></input>
          <button
            type='submit'
            className='bg-orange-400 p-3 w-[20%] font-bold rounded-r-xl text-white'
            onClick={handleAdd}
          >
            Add
          </button>
        </div>
      </div>
    </div>
  );
}

export default App;
