import { configureStore, createSlice } from "@reduxjs/toolkit";

let schedule = createSlice({
  name: "schedule",
  initialState: [
    { title: "강의 보기", isCheck: false },
    { title: "영화 감상", isCheck: false },
  ],
  reducers: {
    AddTodo(state, inputData) {
      return [...state, { title: inputData.payload, isCheck: false }];
    },
    DeleteTodo(state, inputData) {
      let delIndex = state.findIndex((e) => e.title === inputData.payload);
      console.log(delIndex);
      state.splice(delIndex, 1);
      return state;
    },
    ChangeChecked(state, inputData) {
      let changeIndex = state.findIndex((e) => e.title === inputData.payload);
      state[changeIndex].isCheck = !state[changeIndex].isCheck;
      return state;
    },
  },
});

export let { AddTodo, DeleteTodo, ChangeChecked } = schedule.actions;

export default configureStore({
  reducer: {
    schedule: schedule.reducer,
  },
});
